/**
 * @file Qualifier.js
 * @description Annotation class for @Qualifier.
 * 
 * Used to mark a property or class with a named qualifier for dependency injection.
 */
class Qualifier {
  /**
   * @param {string[]} args - Array of arguments for the qualifier (e.g., ['MyService'])
   */
  constructor(args = []) {
    /**
     * Name of the qualifier
     * @type {string}
     */
    this.name = args[0] || null;
  }
}

module.exports = Qualifier;
